#include <stdio.h>
#include <string.h>
#include <stdbool.h>

bool is_interleave(const char *s1, const char *s2, const char *s3) {
    int m = strlen(s1), n = strlen(s2), p = strlen(s3);
    if (m + n != p) return false;
    bool dp[21][21] = {false};
    dp[0][0] = true;
    for (int i = 0; i <= m; ++i) {
        for (int j = 0; j <= n; ++j) {
            if (i == 0 && j == 0) continue;
            int k = i + j - 1; // index in s3
            bool ok = false;
            if (i > 0 && s1[i-1] == s3[k]) ok = ok || dp[i-1][j];
            if (j > 0 && s2[j-1] == s3[k]) ok = ok || dp[i][j-1];
            dp[i][j] = ok;
        }
    }
    return dp[m][n];
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    getchar(); // consume newline after T
    char s1[22], s2[22], s3[42];
    for (int tc = 0; tc < T; ++tc) {
        fgets(s1, sizeof(s1), stdin);
        s1[strcspn(s1, "\n")] = '\0';
        fgets(s2, sizeof(s2), stdin);
        s2[strcspn(s2, "\n")] = '\0';
        fgets(s3, sizeof(s3), stdin);
        s3[strcspn(s3, "\n")] = '\0';
        printf("%s\n", is_interleave(s1, s2, s3) ? "True" : "False");
    }
    return 0;
}

