import sys

def is_interleave(s1, s2, s3):
    m, n, p = len(s1), len(s2), len(s3)
    if m + n != p:
        return False
    dp = [[False] * (n + 1) for _ in range(m + 1)]
    dp[0][0] = True
    for i in range(m + 1):
        for j in range(n + 1):
            if i == 0 and j == 0:
                continue
            k = i + j - 1
            if i > 0 and s1[i - 1] == s3[k]:
                dp[i][j] = dp[i][j] or dp[i - 1][j]
            if j > 0 and s2[j - 1] == s3[k]:
                dp[i][j] = dp[i][j] or dp[i][j - 1]
    return dp[m][n]

data = sys.stdin.read().splitlines()
if not data:
    sys.exit()
T = int(data[0].strip())
idx = 1
out = []
for _ in range(T):
    s1 = data[idx] if idx < len(data) else ''
    s2 = data[idx + 1] if idx + 1 < len(data) else ''
    s3 = data[idx + 2] if idx + 2 < len(data) else ''
    idx += 3
    out.append('True' if is_interleave(s1, s2, s3) else 'False')
print('\n'.join(out))

